export function getBlogPost(slug: string): BlogPost | null {
  return blogPosts.find((p) => p.slug === slug) || null
}

/**
 * Primary money page for a post (R1). Falls back to 'tmcp' — the highest-LTV
 * default — when a post doesn't declare one. Templates read this to render the
 * prominent contextual money link (R2).
 */
export function getBlogPrimaryMoneyPage(slug: string): MoneyPage {
  return getBlogPost(slug)?.primaryMoneyPage ?? 'tmcp'
}
